   113→  const userId = req.user.userId
   114→  const { title = 'Glucolyse Test', body = 'Push notifications are working!' } = req.body
   115→  try {
   116→    const result = await sendNotificationToUser(userId, title, body, 'Alert')
   117→    if (result.success) {
   118→      res.json({ success: true, messageId: result.messageId })
   119→    } else {
   120→      res.status(400).json({ success: false, reason: result.reason, message: result.message })
   121→    }
   122→  } catch (err) {
   123→    res.status(500).json({ error: 'Test failed', message: err.message })
   124→  }
   125→}
