   127→/** Legacy direct-insert route (kept for backward compat) */
   128→export async function sendNotification(req, res) {
   129→  const { userId, type, message } = req.body
   130→  if (!userId || !type || !message) {
   131→    return res.status(400).json({ error: 'All fields required' })
   132→  }
   133→  try {
   134→    const result = await pool.query(
   135→      'INSERT INTO notifications (user_id, type, message) VALUES ($1, $2, $3) RETURNING *',
   136→      [userId, type, message]
   137→    )
   138→    res.status(201).json(result.rows[0])
   139→  } catch {
   140→    res.status(500).json({ error: 'Failed to send notification' })
   141→  }
   142→}
